const remainingCapFor = (
  policy: number,
  items: Item[],
  remainingCaps: Map<number, number>,
): number => remainingCaps.get(policy) ?? policyCap(items);

const processClaim = (
  step: ClaimStep,
  steps: Step[],
  remainingCaps: Map<number, number>,
): ClaimResult => {
  const { items } = steps[step.policy] as QuoteStep;
  const desired = totalPayout(step.incident.damages, items);
  const available = remainingCapFor(step.policy, items, remainingCaps);
  const payout = Math.min(desired, available);
  const remainingCap = available - payout;
  remainingCaps.set(step.policy, remainingCap);
  return { payout, remainingCap };
};
